mapper.insert:
/* 파티션 테이블 추가: postgresPartitionMapper.createRangePartitionTable */
create table ${partitionTableName}
partition of ${tableName}
for values
from ('${fromDate}') to ('${toDate}')

    partition by hash (${hashField})

/* 서브파티션 테이블 추가: postgresPartitionMapper.createSubHashPartitionTable */
create table ${subPartitionTableName}
    partition of ${partitionTableName}
    for values
    with (modulus ${moduleSize}, remainder ${moduleIndex})

mapper.select:
/* 특정파티션 이전 시점의 모든 파티션명 조회 : postgresPartitionMapper.getPrevPartitionTableNames */
select
    child.relname as partition_table_name
from
    pg_inherits inh
        join pg_class parent on inh.inhparent = parent.oid
        join pg_class child on inh.inhrelid = child.oid
where 1=1
  and parent.relname = #{tableName}
  and child.relname <= #{partitionTableName}
